def count_inversions(arr):
    if not arr or len(arr) < 2:
        return 0

    return _merge_sort_and_count(arr, 0, len(arr) - 1)

def _merge_sort_and_count(arr, low, high):
    inversions = 0
    if low < high:
        mid = (low + high) // 2
        inversions += _merge_sort_and_count(arr, low, mid)
        inversions += _merge_sort_and_count(arr, mid + 1, high)
        inversions += _merge_and_count_split_inversions(arr, low, mid, high)
    return inversions

def _merge_and_count_split_inversions(arr, low, mid, high):
    temp = [0] * (high - low + 1) 

    i, j, k = low, mid + 1, 0 
    inversions = 0

    while i <= mid and j <= high:
        if arr[i] <= arr[j]:
            temp[k] = arr[i]
            i += 1
        else:
            temp[k] = arr[j]
            j += 1
            inversions += (mid - i + 1) 
        k += 1

    while i <= mid:
        temp[k] = arr[i]
        i += 1
        k += 1

    while j <= high:
        temp[k] = arr[j]
        j += 1
        k += 1

    for x in range(low, high + 1):
        arr[x] = temp[x - low]

    return inversions
